Hello,
  I am trying to compile a simple void function in latest (devel) iverilog, Without "void" it works, albeit with a warning (valid one). However, with "void", I get an error. Please see below for code and commands:

Working: iverilog -g2012 void_fn.sv 
Not working: iverilog -g2012 -DBUG void_fn.sv 

Please look into the issue.

Thanks
Ani

// code void_fn.sv
`ifndef VW_IVL_GO2UVM_PKG
  `define VW_IVL_GO2UVM_PKG

package vw_ivl_go2uvm_pkg;
  int uvm_err_counter;
  int uvm_warn_counter;
  int uvm_info_counter;


  `ifndef BUG
  function uvm_count_warn();
    uvm_warn_counter++;
  endfunction : uvm_count_warn

  function uvm_count_err();
    uvm_err_counter++;
  endfunction : uvm_count_err


  function uvm_count_info();
    uvm_info_counter++;
  endfunction : uvm_count_info

`else 
  function void uvm_count_err();
    uvm_err_counter++;
  endfunction : uvm_count_err

  function void uvm_count_warn();
    uvm_warn_counter++;
  endfunction : uvm_count_warn

  function void uvm_count_info();
    uvm_info_counter++;
  endfunction : uvm_count_info
 `endif // BUG


endpackage : vw_ivl_go2uvm_pkg


`endif //  VW_IVL_GO2UVM_PKG

module top;
  import vw_ivl_go2uvm_pkg::*;

  initial begin
    uvm_count_info();
  end

endmodule : top


